import OpenAI from "openai";

const client = new OpenAI();

const response = await client.chat.completions.create({
  model: "gpt-4o",
  messages: [
    { role: "system", content: "You are a code reviewer. Be concise and critical." },
    { role: "user", content: "Review this function.\n```js\nfunction add(a,b){return a+b}\n```" },
    { role: "assistant", content: "{ \"issues\": [\"No type validation\"], \"rating\": 6 }" },
    { role: "user", content: "Review this.\n```js\nasync function fetchUser(id){return await db.find(id)}\n```\nThink step by step." },
  ],
  response_format: {
    type: "json_schema",
    json_schema: {
      name: "review",
      schema: {
        type: "object",
        properties: {
          issues: { type: "array", items: { type: "string" } },
          rating: { type: "number" }
        },
        required: ["issues", "rating"],
        additionalProperties: false
      },
      strict: true
    }
  }
});

console.log(JSON.parse(response.choices[0].message.content!));

import OpenAI from 'openai';
import { z } from 'zod';
import { zodResponseFormat } from 'openai/helpers/zod';

const client = new OpenAI();

const ArticleSummary = z.object({
  headline: z.string(),
  key_points: z.array(z.string()).max(3),
  sentiment: z.enum(['positive', 'neutral', 'negative']),
});

const response = await client.beta.chat.completions.parse({
  model: 'gpt-4o-mini',
  messages: [{ role: 'user', content: 'Summarize: OpenAI launches o3 model with reasoning.' }],
  response_format: zodResponseFormat(ArticleSummary, 'article_summary'),
});

const summary = response.choices[0].message.parsed;
console.log(summary.headline, summary.sentiment);

