import OpenAI from 'openai';

const client = new OpenAI();
const tools = [{
  type: 'function' as const,
  function: {
    name: 'get_stock_price',
    description: 'Returns the current stock price for a given ticker symbol.',
    parameters: { type: 'object', properties: { ticker: { type: 'string' } }, required: ['ticker'] },
  },
}];

const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
  { role: 'user', content: 'What is the price of NVDA?' },
];

for (let i = 0; i < 10; i++) {
  const response = await client.chat.completions.create({ model: 'gpt-4o', tools, messages });
  const choice = response.choices[0];
  if (choice.finish_reason === 'stop') { console.log(choice.message.content); break; }
  const call = choice.message.tool_calls![0];
  const args = JSON.parse(call.function.arguments);
  const result = { price: args.ticker === 'NVDA' ? 875.42 : 0 };
  messages.push(choice.message);
  messages.push({ role: 'tool', tool_call_id: call.id, content: JSON.stringify(result) });
}

import OpenAI from 'openai';

const client = new OpenAI();

async function safeCompletion(userMessage: string, context: string) {
  const modInput = await client.moderations.create({ model: 'omni-moderation-latest', input: userMessage });
  if (modInput.results[0].flagged) throw new Error('Input flagged by moderation');

  const completion = await client.chat.completions.create({
    model: 'gpt-4o',
    logprobs: true,
    response_format: { type: 'json_schema', json_schema: { name: 'answer', strict: true, schema: { type: 'object', properties: { answer: { type: 'string' }, confident: { type: 'boolean' } }, required: ['answer', 'confident'], additionalProperties: false } } },
    messages: [
      { role: 'system', content: `Answer using only the context below. If unsure, set confident=false.\n<context>${context}</context>` },
      { role: 'user', content: `<user_input>${userMessage}</user_input>` }
    ]
  });

  const modOutput = await client.moderations.create({ model: 'omni-moderation-latest', input: completion.choices[0].message.content! });
  if (modOutput.results[0].flagged) throw new Error('Output flagged by moderation');

  return JSON.parse(completion.choices[0].message.content!);
}
